73	/// A publisher that allows sending data through a stream.
74	/// A Publisher is declared by a [`Session`](crate::api::session::Session) for a given key expression
75	/// with method [`Session::declare_publisher`](crate::api::session::Session::declare_publisher).
76	///
77	/// Publishers are automatically undeclared when dropped.
78	///
79	/// # Examples
80	/// ```
81	/// # #[tokio::main]
82	/// # async fn main() {
83	///
84	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
85	/// let publisher = session.declare_publisher("key/expression").await.unwrap();
86	/// publisher.put("value").await.unwrap();
87	/// # format!("{publisher:?}");
88	/// # }
89	/// ```
90	///
91	///
92	/// `Publisher` implements the `Sink` trait which is useful for forwarding
93	/// streams to zenoh.
94	/// ```
95	/// # #[tokio::main]
96	/// # async fn main() {
97	/// use futures::StreamExt;
98	///
99	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
100	/// let mut subscriber = session.declare_subscriber("key/expression").await.unwrap();
101	/// let publisher = session.declare_publisher("another/key/expression").await.unwrap();
102	/// # tokio::task::spawn(async move {
103	/// #     session.put("key/expression", "value").await.unwrap();
104	/// #     tokio::time::sleep(std::time::Duration::from_secs(1)).await;
105	/// #     session.close().await.unwrap();
106	/// # });
107	/// subscriber.stream().map(Ok).forward(publisher).await.unwrap();
108	/// # }
109	/// ```
110	#[derive(Debug)]
111	pub struct Publisher<'a> {
112	    pub(crate) session: WeakSession,
113	    pub(crate) id: Id,
114	    pub(crate) key_expr: KeyExpr<'a>,
115	    pub(crate) encoding: Encoding,
116	    pub(crate) congestion_control: CongestionControl,
117	    pub(crate) priority: Priority,
118	    pub(crate) is_express: bool,
119	    pub(crate) destination: Locality,
120	    #[cfg(feature = "unstable")]
121	    pub(crate) reliability: Reliability,
122	    pub(crate) matching_listeners: Arc<Mutex<HashSet<Id>>>,
123	    pub(crate) undeclare_on_drop: bool,
124	    pub(crate) sync_group: SyncGroup,
125	}
