241	    /// Publish the data. The subscribers matching the Publisher's key expression will receive the
242	    /// [`Sample`] with [`kind`](crate::sample::Sample::kind) [SampleKind::Put](crate::sample::SampleKind::Put).
243	    ///
244	    /// The builder allows customizing the publication: add the timestamp,
245	    /// attachment, etc. Some fields are pre-filled with the Publisher's configuration and can
246	    /// be overridden.
247	    ///
248	    /// # Examples
249	    /// ```
250	    /// # #[tokio::main]
251	    /// # async fn main() {
252	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
253	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
254	    /// publisher.put("value").await.unwrap();
255	    /// # }
256	    /// ```
257	    #[inline]
258	    pub fn put<IntoZBytes>(&self, payload: IntoZBytes) -> PublisherPutBuilder<'_>
259	    where
260	        IntoZBytes: Into<ZBytes>,
261	    {
262	        PublicationBuilder {
263	            publisher: self,
264	            kind: PublicationBuilderPut {
265	                payload: payload.into(),
266	                encoding: self.encoding.clone(),
267	            },
268	            timestamp: None,
269	            #[cfg(feature = "unstable")]
270	            source_info: None,
271	            attachment: None,
272	        }
273	    }
