302	    /// Return the [`MatchingStatus`] of the publisher.
303	    ///
304	    /// [`MatchingStatus::matching`] will return true if there exist Subscribers
305	    /// matching the Publisher's key expression and false otherwise.
306	    ///
307	    /// # Examples
308	    /// ```
309	    /// # #[tokio::main]
310	    /// # async fn main() {
311	    ///
312	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
313	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
314	    /// let matching_subscribers: bool = publisher
315	    ///     .matching_status()
316	    ///     .await
317	    ///     .unwrap()
318	    ///     .matching();
319	    /// # }
320	    /// ```
321	    pub fn matching_status(&self) -> impl Resolve<ZResult<MatchingStatus>> + '_ {
322	        zenoh_core::ResolveFuture::new(async move {
323	            self.session.matching_status(
324	                self.key_expr(),
325	                self.destination,
326	                MatchingStatusType::Subscribers,
327	            )
328	        })
329	    }
