331	    /// Return a [`MatchingListener`](crate::api::matching::MatchingListener) for this Publisher.
332	    ///
333	    /// The [`MatchingListener`](crate::api::matching::MatchingListener) will send a notification each time the [`MatchingStatus`](crate::api::matching::MatchingStatus) of
334	    /// the Publisher changes.
335	    ///
336	    /// # Examples
337	    /// ```no_run
338	    /// # #[tokio::main]
339	    /// # async fn main() {
340	    ///
341	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
342	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
343	    /// let matching_listener = publisher.matching_listener().await.unwrap();
344	    /// while let Ok(matching_status) = matching_listener.recv_async().await {
345	    ///     if matching_status.matching() {
346	    ///         println!("Publisher has matching subscribers.");
347	    ///     } else {
348	    ///         println!("Publisher has NO MORE matching subscribers.");
349	    ///     }
350	    /// }
351	    /// # }
352	    /// ```
353	    pub fn matching_listener(&self) -> MatchingListenerBuilder<'_, DefaultHandler> {
354	        MatchingListenerBuilder {
355	            session: &self.session,
356	            key_expr: &self.key_expr,
357	            destination: self.destination,
358	            matching_listeners: &self.matching_listeners,
359	            matching_status_type: MatchingStatusType::Subscribers,
360	            handler: DefaultHandler::default(),
361	            parent_callback_sync_group_notifier: self.sync_group.notifier(),
362	        }
363	    }
