365	    /// Undeclare the [`Publisher`], informing the network that it needn't optimize publications for its key expression anymore.
366	    ///
367	    /// # Examples
368	    /// ```
369	    /// # #[tokio::main]
370	    /// # async fn main() {
371	    ///
372	    /// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
373	    /// let publisher = session.declare_publisher("key/expression").await.unwrap();
374	    /// publisher.undeclare().await.unwrap();
375	    /// # }
376	    /// ```
377	    pub fn undeclare(self) -> PublisherUndeclaration<'a> {
378	        UndeclarableSealed::undeclare_inner(self, ())
379	    }
380	
381	    fn undeclare_impl(&mut self) -> ZResult<()> {
382	        // set the flag first to avoid double panic if this function panics
383	        self.undeclare_on_drop = false;
384	        let ids: Vec<Id> = zlock!(self.matching_listeners).drain().collect();
385	        for id in ids {
386	            self.session.undeclare_matches_listener_inner(id)?
387	        }
388	        self.session.undeclare_publisher_inner(self.id)
389	    }
390	
391	    #[zenoh_macros::internal]
392	    pub fn session(&self) -> &WeakSession {
393	        &self.session
394	    }
395	}
