435	impl<'a> PublisherUndeclaration<'a> {
436	    #[zenoh_macros::internal_or_unstable]
437	    /// Block in undeclare operation until all currently running instances of matching listeners' callbacks (if any) return.
438	    pub fn wait_callbacks(mut self) -> Self {
439	        self.wait_callbacks = true;
440	        self
441	    }
