444	impl Resolvable for PublisherUndeclaration<'_> {
445	    type To = ZResult<()>;
446	}
447	
448	impl Wait for PublisherUndeclaration<'_> {
449	    fn wait(mut self) -> <Self as Resolvable>::To {
450	        self.publisher.undeclare_impl()?;
451	        if self.wait_callbacks {
452	            self.publisher.sync_group.wait();
453	        }
454	        Ok(())
455	    }
456	}
