458	impl IntoFuture for PublisherUndeclaration<'_> {
459	    type Output = <Self as Resolvable>::To;
460	    type IntoFuture = Ready<<Self as Resolvable>::To>;
461	
462	    fn into_future(self) -> Self::IntoFuture {
463	        std::future::ready(self.wait())
464	    }
465	}
